    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Acdn.shopify.com%2Fs%2Ffiles%2F1%2F0646%2F3671%2F5163%2Ffiles%2FGELRESOLUTIONYanguas_1_db6b025d-cbc1-4669-8451-ddbe6e3e3528.jpg%3Fv%3D1764335256&feedId=98176&k=49ef3964d7c101008024307f5ce9154b98e3fede",
    "ean": "4571633426056",
