    "id": 357,
    "slug": "asics-gel-resolution-x-padel-ss26-mike-yanguas-zapatillas-43311667602",
    "name": "ASICS GEL-RESOLUTION X Padel SS26 MIKE YANGUAS (sapatilhas)",
    "brand": "ASICS",
