    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Acdn.shopify.com%2Fs%2Ffiles%2F1%2F0646%2F3671%2F5163%2Ffiles%2F8421.jpg%3Fv%3D1725950445&feedId=98176&k=f422e8272c9a2725e839368d9aeef290e4922bfa",
