    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Acdn.shopify.com%2Fs%2Ffiles%2F1%2F0646%2F3671%2F5163%2Ffiles%2FWILSONDEFYPROV1Padel22025JAVIGARRIDO_Pala_1.jpg%3Fv%3D1739795132&feedId=98176&k=9547c2ea1ee83be03fbcfc32903ecdb7ff32629f",
